package worker

import (
	"context"
	"sync"
)

type Handler func(ctx context.Context, job Job)

type Job struct {
	ID      string
	Payload []byte
}

type Pool struct {
	handler Handler
	size    int
}

func NewPool(handler Handler, size int) *Pool {
	if size < 1 {
		size = 1
	}
	return &Pool{handler: handler, size: size}
}

// Run launches size worker goroutines that drain jobs until the channel is
// closed or ctx is cancelled, then waits for every worker to exit.
func (p *Pool) Run(ctx context.Context, jobs <-chan Job) {
	var wg sync.WaitGroup
	wg.Add(p.size)
	for i := 0; i < p.size; i++ {
		go func() {
			defer wg.Done()
			for {
				select {
				case <-ctx.Done():
					return
				case job, ok := <-jobs:
					if !ok {
						return
					}
					p.handler(ctx, job)
				}
			}
		}()
	}
	wg.Wait()
}
